- Use `nest new project-name` to create a new NestJS project.
- Install dependencies with `npm install @nestjs/microservices`.
- Configure Kafka in `app.module.ts`:
  ```typescript
  import { ClientsModule, Transport } from '@nestjs/microservices';

  const kafkaConfig = {
    transport: Transport.KAFKA,
    options: {
      client: {
        brokers: ['localhost:9092'],
      },
      consumer: {
        groupId: 'test-group',
      },
    },
  };

  @Module({
    imports: [ClientsModule.register([kafkaConfig])],
  })
  export class AppModule {}
  ```
- Use `@EventPattern` for event-driven communication.
- Use `emit()` method to send messages:
  ```typescript
  import { ClientKafka } from '@nestjs/microservices';

  @Injectable()
  export class KafkaService {
    constructor(private readonly client: ClientKafka) {}

    sendMessage(message: any) {
      this.client.emit('event_name', message);
    }
  }
  ```
- Ensure Kafka broker is running and accessible.
- Check for latest versions on [NestJS official website](https://nestjs.com/) or [npm page](https://www.npmjs.com/package/@nestjs/microservices).

